namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string CourseCode { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string StudentName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new Department { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and software systems." },
            new Department { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and mathematical reasoning." },
            new Department { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and linguistic analysis." },
            new Department { Id = 4, Code = "HIST", Name = "History", Description = "Study of past events and their impact on society." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new Course { Id = 1, DepartmentId = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00-9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education.", IsFeatured = true },
            new Course { Id = 2, DepartmentId = 1, CourseCode = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Algorithm analysis and design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30 AM-12:00 PM", InstructorName = "Dr. James Wright", InstructorBio = "Dr. Wright specializes in algorithm optimization and has published over 30 research papers.", IsFeatured = true },
            new Course { Id = 3, DepartmentId = 1, CourseCode = "CS301", Title = "Database Systems", Description = "Design and implementation of relational databases. SQL, normalization, transaction processing, and query optimization.", Credits = 3, Schedule = "Mon/Wed 2:00-3:30 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked in industry for 10 years at major tech companies before joining academia.", IsFeatured = false },

            // Mathematics
            new Course { Id = 4, DepartmentId = 2, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students.", IsFeatured = true },
            new Course { Id = 5, DepartmentId = 2, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00-2:30 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park's research focuses on applied linear algebra and numerical methods.", IsFeatured = false },
            new Course { Id = 6, DepartmentId = 2, CourseCode = "MATH301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00-11:50 AM", InstructorName = "Dr. David Patel", InstructorBio = "Dr. Patel brings practical experience from his work in actuarial science and data analytics.", IsFeatured = false },

            // English
            new Course { Id = 7, DepartmentId = 3, CourseCode = "ENG101", Title = "College Writing", Description = "Development of writing skills through essays, research papers, and critical analysis. Focus on clarity and argumentation.", Credits = 3, Schedule = "Tue/Thu 9:00-10:30 AM", InstructorName = "Prof. Rachel Adams", InstructorBio = "Prof. Adams is a published author and has taught writing at the university level for 20 years.", IsFeatured = false },
            new Course { Id = 8, DepartmentId = 3, CourseCode = "ENG201", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present. Includes poetry, fiction, and drama.", Credits = 3, Schedule = "Mon/Wed 3:00-4:30 PM", InstructorName = "Dr. Thomas Greene", InstructorBio = "Dr. Greene is a specialist in 20th-century American fiction and has authored three books on the subject.", IsFeatured = true },
            new Course { Id = 9, DepartmentId = 3, CourseCode = "ENG301", Title = "Creative Writing Workshop", Description = "Workshop-based course focusing on fiction and poetry. Students produce and critique original work.", Credits = 3, Schedule = "Fri 1:00-4:00 PM", InstructorName = "Prof. Lisa Morgan", InstructorBio = "Prof. Morgan is a novelist with four published works and a National Book Award finalist.", IsFeatured = false },

            // History
            new Course { Id = 10, DepartmentId = 4, CourseCode = "HIST101", Title = "World Civilizations", Description = "Survey of major world civilizations from ancient times to the modern era. Explores cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00-1:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres has conducted archaeological research across three continents.", IsFeatured = false },
            new Course { Id = 11, DepartmentId = 4, CourseCode = "HIST201", Title = "The American Civil War", Description = "In-depth study of the causes, course, and consequences of the American Civil War and Reconstruction.", Credits = 3, Schedule = "Tue/Thu 3:00-4:30 PM", InstructorName = "Dr. Angela Washington", InstructorBio = "Dr. Washington is a leading scholar on Civil War era history and has consulted for documentary films.", IsFeatured = true },
            new Course { Id = 12, DepartmentId = 4, CourseCode = "HIST301", Title = "Modern European History", Description = "Europe from the French Revolution to the present. Covers industrialization, world wars, and European integration.", Credits = 3, Schedule = "Mon/Wed 10:00-11:30 AM", InstructorName = "Dr. Peter Schmidt", InstructorBio = "Dr. Schmidt studied at Oxford and specializes in 20th-century European political history.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.ToLowerInvariant().Contains(term) ||
                c.CourseCode.ToLowerInvariant().Contains(term));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request) => true;
}

