@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - State University</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" action="/courses" class="mb-4">
    @if (DepartmentId.HasValue)
    {
        <input type="hidden" name="DepartmentId" value="@DepartmentId" />
    }
    <div class="input-group">
        <input type="text" name="Search" value="@Search" class="form-control" placeholder="Search courses by title or code..." />
        <button type="submit" class="btn btn-primary">Search</button>
    </div>
</form>

<div class="mb-4">
    <strong>Filter by Department:</strong>
    <a href="/courses" class="btn btn-sm btn-outline-secondary ms-2">All</a>
    @foreach (var dept in CatalogService.GetDepartments())
    {
        <a href="/courses?DepartmentId=@dept.Id" class="btn btn-sm btn-outline-secondary ms-1">@dept.Name</a>
    }
</div>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Department</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = CatalogService.GetDepartment(course.DepartmentId);
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@dept?.Name</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enroll - State University</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for the selected course has been received.</p>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <EditForm Model="Model" method="post" FormName="enrollment" OnValidSubmit="HandleSubmit">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Student Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="0">-- Select a Course --</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.CourseCode - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool _submitted;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(Model);
        _submitted = true;
    }
}

